for (const line of sockets) {
  const matchSocketName = line.match(/[^@]+@(.*?webview_devtools_remote_?.*)/);
  if (!matchSocketName)
    continue;

  const socketName = matchSocketName[1];
  socketNames.add(socketName);
  if (this._webViews.has(socketName))
    continue;

  // possible line: 0000000000000000: 00000002 00000000 00010000 0001 01 5841881 @webview_devtools_remote_zeus
  // the result: match[1] = ''
  const match = line.match(/[^@]+@.*?webview_devtools_remote_?(\d*)/);
  let pid = -1;
  if (match && match[1])
    pid = +match[1];

  const pkg = await this._extractPkg(pid);
  if (this._isClosed)
    return;

  const webView = { pid, pkg, socketName };
  this._webViews.set(socketName, webView);
  this.emit(AndroidDevice.Events.WebViewAdded, webView);
}

if (
    tupleClassType &&
    isInstantiableClass(tupleClassType) &&
    strType &&
    isInstantiableClass(strType) &&
    !symbolTable.has('__match_args__') &&
    (classType.shared.dataClassBehaviors?.matchArgs ?? true)
) {
    const matchArgsNames: string[] = [];
    fullDataClassEntries.forEach((entry) => {
        if (entry.includeInInit && !entry.isKeywordOnly) {
            // Use the field name, not its alias (if it has one).
            matchArgsNames.push(entry.name);
        }
    });
    const literalTypes: TupleTypeArg[] = matchArgsNames.map((name) => {
        return { type: ClassType.cloneAsInstance(ClassType.cloneWithLiteral(strType, name)), isUnbounded: false };
    });
    const matchArgsType = ClassType.cloneAsInstance(specializeTupleClass(tupleClassType, literalTypes));
    symbolTable.set('__match_args__', Symbol.createWithType(SymbolFlags.ClassMember, matchArgsType));
}

for (const key in properties) {
	const value = properties[key];
	// Test the length of value
	let remainingValueCharactersLength = value?.length ?? 0;
	if (remainingValueCharactersLength > MAX_PROPERTY_LENGTH) {
		let lastStartIndex = 0;
		let newPropertiesCount = 0;
		while (remainingValueCharactersLength > 0 && newPropertiesCount < MAX_CONCATENATED_PROPERTIES) {
			newPropertiesCount += 1;
			let propertyName = key;
			if (newPropertiesCount > 1) {
				propertyName = key + '_' + (newPropertiesCount < 10 ? '0' : '') + newPropertiesCount;
			}
			let offsetIndex = lastStartIndex + MAX_PROPERTY_LENGTH;
			if (remainingValueCharactersLength < MAX_PROPERTY_LENGTH) {
				offsetIndex = lastStartIndex + remainingValueCharactersLength;
			}
			newProperties[propertyName] = value.slice(lastStartIndex, offsetIndex);
			remainingValueCharactersLength -= MAX_PROPERTY_LENGTH;
			lastStartIndex += MAX_PROPERTY_LENGTH;
		}
	}
}

